mapper.select:
select sf.flow_id, sf.product_id, p.product_name, p.specification, sf.flow_type, sf.change_quantity,
       sf.before_quantity, sf.after_quantity, sf.order_number, sf.task_no, sf.business_time,
       sf.create_by, sf.create_time, sf.remark
from t_stock_flow sf
left join t_product p on p.product_id = sf.product_id


        and sf.product_id = #{productId}


        and p.product_name like concat('%', #{productName}, '%')


        and sf.flow_type = #{flowType}


        and sf.order_number like concat('%', #{orderNumber}, '%')


        and sf.task_no like concat('%', #{taskNo}, '%')


        and sf.business_time >= #{params.beginTime}


        and sf.business_time <= #{params.endTime}


order by sf.flow_id desc
